local G = DYCLegendary local require = G.DYCModRequire local TableContains = G.lib.TableContains local TableAdd = G.lib.TableAdd local TableRemoveValue = G.lib.TableRemoveValue local spls = {require( "dyc_spl_laserbeam" ), require( "dyc_spl_firefissure" ), require( "dyc_spl_clusterzaps" ), require( "dyc_spl_bladeofwind" ),} local spells = {} function spells:AddSpell(name, s) name = string.lower(name) if spells[name] then error( "Spell already exists: "..name) end spells[name] = s end function spells:GetSpell(name) name = string.lower(name) return spells[name] end for k, v in pairs(spls) do spells:AddSpell(v.name, v) end return spells 